#!/bin/bash
# Fix dashboard_live.html - restore page body destroyed by nav regex
# Run on GCP server: bash fix_dashboard.sh

cd ~/deploy || exit 1

# Backup current file
cp dashboard_live.html dashboard_live.html.bak 2>/dev/null

# Decode and write fixed file
python3 << 'INNEREOF'
import gzip, base64
data = ""
content = gzip.decompress(base64.b64decode(data))
open("dashboard_live.html", "wb").write(content)
print(f"Written {len(content)} bytes to dashboard_live.html")
INNEREOF

# Verify key elements exist
echo ""
echo "Verification:"
grep -c "<table" dashboard_live.html | xargs -I{} echo "  table count: {}"
grep -c "<tbody" dashboard_live.html | xargs -I{} echo "  tbody count: {}"
grep -c "headerRow" dashboard_live.html | xargs -I{} echo "  headerRow refs: {}"
grep -c "stockCount" dashboard_live.html | xargs -I{} echo "  stockCount refs: {}"
grep -c "site-nav" dashboard_live.html | xargs -I{} echo "  site-nav refs: {}"

# Restart server
echo ""
echo "Restarting server..."
pkill -f ws_server.py
sleep 2
nohup venv/bin/python3 ws_server.py >> server.log 2>&1 &
sleep 3

# Verify routes
echo ""
echo "Verifying routes..."
for route in "/" "/paper" "/sectors" "/rsi" "/rsi-analysis" "/admin"; do
    code=$(curl -s -o /dev/null -w "%{http_code}" "http://localhost:8080$route")
    echo "  $route -> $code"
done
echo ""
echo "Done! Check http://35.223.238.30:8080/"
